/**
 * Vestax VCI-380 controller script for Mixxx
 * Generated by SpotifyController project
 *
 * Handles button logic that needs more than simple CC mapping:
 * play toggle, cue behavior, sync, jog wheel, hot cues, browse encoder.
 */

var VestaxVCI380 = {};

VestaxVCI380.init = function(id, debugging) {
    print("Vestax VCI-380: Initializing...");
    // Nothing to initialize for now — the controller sends standard MIDI
    // and doesn't need SysEx handshake.
    print("Vestax VCI-380: Ready.");
};

VestaxVCI380.shutdown = function() {
    print("Vestax VCI-380: Shutdown.");
};

// -- Helper: get channel group from MIDI status byte --
VestaxVCI380._groupFromStatus = function(status) {
    // 0x97 / 0xB7 = Channel 8 = Deck A = [Channel1]
    // 0x98 / 0xB8 = Channel 9 = Deck B = [Channel2]
    var channel = status & 0x0F;
    if (channel === 7) return "[Channel1]";
    if (channel === 8) return "[Channel2]";
    return "[Channel1]";  // fallback
};

// -- Transport: Play --
VestaxVCI380.playButton = function(channel, control, value, status, group) {
    if (value === 0) return;  // ignore note-off
    var playing = engine.getValue(group, "play");
    engine.setValue(group, "play", playing ? 0 : 1);
};

// -- Transport: Cue --
VestaxVCI380.cueButton = function(channel, control, value, status, group) {
    if (value > 0) {
        engine.setValue(group, "cue_default", 1);
    } else {
        engine.setValue(group, "cue_default", 0);
    }
};

// -- Transport: Sync --
VestaxVCI380.syncButton = function(channel, control, value, status, group) {
    if (value === 0) return;
    engine.setValue(group, "sync_enabled", !engine.getValue(group, "sync_enabled"));
};

// -- Transport: Load --
VestaxVCI380.loadButton = function(channel, control, value, status, group) {
    if (value === 0) return;
    engine.setValue(group, "LoadSelectedTrack", 1);
};

// -- Jog Wheel --
VestaxVCI380.jogWheel = function(channel, control, value, status, group) {
    // value is 0-127: 0-63 = backward, 64 = center, 65-127 = forward
    var newValue = value - 64;
    // Scale for comfortable scratching/nudging
    var multiplier = 1.0;
    if (engine.getValue(group, "play") === 1) {
        // Nudge mode when playing
        multiplier = 0.5;
    } else {
        // Scratch mode when paused
        multiplier = 2.0;
    }
    engine.setValue(group, "jog", newValue * multiplier);
};

// -- Hot Cue Pads --
VestaxVCI380.hotcue = function(channel, control, value, status, group) {
    if (value === 0) return;  // ignore note-off
    // Map MIDI note to hotcue number: 0x3C=1, 0x3D=2, 0x3E=3, 0x3F=4
    var padNum = control - 0x3C + 1;
    if (padNum < 1 || padNum > 4) return;

    var key = "hotcue_" + padNum + "_activate";
    engine.setValue(group, key, 1);
    // Mixxx auto-sets the cue if it doesn't exist, or jumps to it if it does
};

// -- Browse Encoder --
VestaxVCI380.browseEncoder = function(channel, control, value, status, group) {
    // Relative encoder: 0-63 = clockwise ticks, 65-127 = counter-clockwise
    if (value < 64) {
        // Scroll down
        engine.setValue("[Library]", "MoveDown", value);
    } else {
        // Scroll up
        engine.setValue("[Library]", "MoveUp", 128 - value);
    }
};
